styles:
    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

    :root {
      --sidebar-bg: #DAE4F8;
      --main-bg: #FFFCF8;
      --blue: #448AFF;
      --text: #1a1a1a;
      --muted: #6b6b6b;
      --border-light: #d8dce3;
      --card-hover: #FFEED5;
      --sidebar-width: 248px;
      --font: 'Montserrat', sans-serif;
    }

    html, body { height: 100%; }

    body {
      font-family: var(--font);
      background: var(--main-bg);
      color: var(--text);
      -webkit-font-smoothing: antialiased;
    }

    .app { display: flex; min-height: 100vh; }

    .sidebar {
      width: var(--sidebar-width);
      flex-shrink: 0;
      background: var(--sidebar-bg);
      display: flex;
      flex-direction: column;
      padding: 28px 20px 32px;
      min-height: 100vh;
      transition: width 0.22s ease, padding 0.22s ease;
      position: relative;
    }

    .sidebar__collapse {
      position: absolute;
      top: 14px;
      right: 12px;
      width: 34px;
      height: 34px;
      border: none;
      border-radius: 8px;
      background: transparent;
      color: var(--blue);
      cursor: pointer;
      display: flex;
      align-items: center;
      justify-content: center;
      padding: 0;
    }

    .sidebar__collapse:hover { background: rgba(68, 138, 255, 0.12); }
    .sidebar__collapse svg { width: 22px; height: 22px; display: block; }
    .app.is-sidebar-collapsed .sidebar__collapse { display: none; }

    .sidebar__toggle {
      width: 54px;
      height: 54px;
      margin: 0 auto 18px;
      border: none;
      border-radius: 16px;
      background: rgba(68, 138, 255, 0.12);
      display: none;
      align-items: center;
      justify-content: center;
      cursor: pointer;
    }

    .app.is-sidebar-collapsed .sidebar__toggle { display: flex; }

    .sidebar__toggle img {
      width: 32px;
      height: 32px;
      object-fit: contain;
      filter: brightness(0) saturate(100%) invert(59%) sepia(92%) saturate(2775%) hue-rotate(196deg) brightness(101%) contrast(101%);
    }

    .sidebar__brand {
      display: flex;
      flex-direction: column;
      align-items: center;
      text-align: center;
      margin-bottom: 36px;
    }

    .sidebar__logo {
      width: 120px;
      height: auto;
      display: block;
      filter: brightness(0) saturate(100%) invert(59%) sepia(92%) saturate(2775%) hue-rotate(196deg) brightness(101%) contrast(101%);
      margin-bottom: 4px;
    }

    .sidebar__title {
      font-size: 15px;
      font-weight: 800;
      color: var(--blue);
      letter-spacing: 0.06em;
    }

    .nav { list-style: none; display: flex; flex-direction: column; gap: 6px; }

    .nav a {
      display: flex;
      align-items: center;
      gap: 12px;
      padding: 12px 16px;
      border-radius: 12px;
      color: var(--blue);
      font-size: 14px;
      font-weight: 600;
      text-decoration: none;
      transition: background 0.15s ease;
    }

    .nav a svg { width: 20px; height: 20px; flex-shrink: 0; stroke: currentColor; fill: none; }
    .nav a .nav-icon--saved { stroke: none; }
    .nav a .nav-icon--saved path { fill: currentColor; }
    .nav a .nav-icon--attendance { stroke: none; }
    .nav a .nav-icon--attendance path { fill: currentColor; }
    .nav a .nav-icon--events { stroke: none; }
    .nav a .nav-icon--events path { fill: currentColor; }
    .nav a .nav-icon--home { stroke: none; }
    .nav a .nav-icon--home path { fill: currentColor; }
    .nav a .nav-icon--certificates { stroke: none; }
    .nav a .nav-icon--certificates path { fill: currentColor; }
    .nav a.is-active [class*="nav-icon--"] > g { filter: none; }
    .nav a:hover:not(.is-active) { background: rgba(68, 138, 255, 0.12); }

    .nav a.is-active {
      background: rgba(68, 138, 255, 0.28);
      color: var(--blue);
    }

    .sidebar__spacer { flex: 1; min-height: 24px; }
    .nav--bottom { margin-top: auto; padding-top: 16px; }

    .app.is-sidebar-collapsed .sidebar { width: 102px; padding: 28px 12px 24px; }
    .app.is-sidebar-collapsed .sidebar__brand { display: none; }
    .app.is-sidebar-collapsed .nav a { justify-content: center; gap: 0; padding: 14px 0; font-size: 0; }
    .app.is-sidebar-collapsed .nav a svg { width: 24px; height: 24px; }
    .app.is-sidebar-collapsed .nav a.is-active { width: 56px; margin: 0 auto; }

    .main {
      flex: 1;
      min-width: 0;
      overflow-y: auto;
      padding: 32px 40px 56px;
      background: var(--main-bg);
    }

    .detail-topbar {
      display: flex;
      align-items: center;
      justify-content: space-between;
      gap: 16px;
      margin-bottom: 24px;
    }

    .detail-topbar h1 {
      font-size: clamp(1.75rem, 3vw, 2.25rem);
      font-weight: 700;
      color: var(--blue);
      line-height: 1.15;
    }

    .main__tools { display: flex; align-items: center; gap: 12px; }

    .main__user-name {
      font-size: 14px;
      font-weight: 600;
      color: var(--blue);
      white-space: nowrap;
    }

    .tool-btn {
      width: 40px;
      height: 40px;
      border: none;
      border-radius: 50%;
      background: #e8eef6;
      cursor: pointer;
      display: flex;
      align-items: center;
      justify-content: center;
      color: var(--blue);
    }

    .tool-btn--avatar { background: #c5d9fc; }
    .tool-btn--help { background: #c5d9fc; color: #fff; }
    .tool-btn--help:hover { background: #b5cffc; color: #fff; }
    .tool-btn--help svg { width: 22px; height: 22px; flex-shrink: 0; }
    .tool-btn svg { width: 22px; height: 22px; }

    .detail-hero {
      width: 100%;
      height: 240px;
      overflow: hidden;
      margin-bottom: 28px;
      background: #d4e2f7;
    }

    .detail-hero img {
      width: 100%;
      height: 100%;
      object-fit: cover;
      display: block;
    }

    .detail-head {
      display: grid;
      grid-template-columns: 80px 1fr auto;
      gap: 24px;
      align-items: start;
      padding-bottom: 24px;
    }

    .detail-date { text-align: center; font-weight: 700; line-height: 1.15; }

    .detail-date__month,
    .detail-date__year {
      display: block;
      font-size: 13px;
      font-weight: 600;
      color: var(--text);
    }

    .detail-date__day {
      display: block;
      font-size: 40px;
      font-weight: 800;
      color: var(--blue);
      margin: 4px 0;
      line-height: 1;
    }

    .detail-info h2 {
      font-size: 22px;
      font-weight: 800;
      color: var(--text);
      margin-bottom: 12px;
      line-height: 1.2;
    }

    .detail-meta {
      display: flex;
      flex-direction: column;
      gap: 8px;
      font-size: 14px;
      font-weight: 600;
    }

    .detail-meta__row {
      display: inline-flex;
      align-items: center;
      gap: 8px;
    }

    .detail-meta__row svg { width: 16px; height: 16px; flex-shrink: 0; }
    .detail-meta__row--venue { color: var(--blue); }
    .detail-meta__row--venue svg { stroke: var(--blue); }
    .detail-meta__row--time { color: var(--text); font-weight: 500; }
    .detail-meta__row--time svg { stroke: var(--text); }

    .detail-actions { display: flex; gap: 10px; padding-top: 4px; }

    .detail-icon-btn {
      width: 38px;
      height: 38px;
      border: 1.5px solid var(--blue);
      border-radius: 50%;
      background: var(--main-bg);
      color: var(--blue);
      cursor: pointer;
      display: flex;
      align-items: center;
      justify-content: center;
    }

    .detail-icon-btn svg { width: 17px; height: 17px; }

    .submit-intro {
      font-size: 14px;
      line-height: 1.75;
      color: var(--muted);
      margin: 8px 0 24px;
      font-weight: 500;
    }

    .submit-panel {
      background: var(--sidebar-bg);
      border-radius: 16px;
      padding: 24px 28px;
      margin-bottom: 36px;
    }

    .submit-panel__head {
      display: flex;
      align-items: center;
      gap: 10px;
      margin-bottom: 20px;
      font-size: 15px;
      font-weight: 700;
      color: var(--text);
    }

    .submit-panel__head svg {
      width: 20px;
      height: 20px;
      stroke: var(--blue);
      fill: none;
    }

    .submit-file-list {
      display: flex;
      flex-direction: column;
      gap: 20px;
    }

    .submit-file-row {
      display: flex;
      align-items: flex-start;
      justify-content: space-between;
      gap: 20px;
    }

    .submit-file-row__info { flex: 1; min-width: 0; }

    .submit-file-row__name {
      font-size: 14px;
      font-weight: 700;
      color: var(--text);
      margin-bottom: 6px;
    }

    .submit-file-row__hint {
      font-size: 13px;
      line-height: 1.55;
      color: var(--muted);
      font-weight: 500;
    }

    .submit-file-row__upload {
      position: relative;
      width: 44px;
      height: 44px;
      border-radius: 12px;
      background: var(--main-bg);
      border: 1.5px solid transparent;
      display: flex;
      align-items: center;
      justify-content: center;
      color: var(--blue);
      cursor: pointer;
      flex-shrink: 0;
      transition: border-color 0.18s ease;
    }

    .submit-file-row__upload:hover { border-color: var(--blue); }

    .submit-file-row__upload svg {
      width: 22px;
      height: 22px;
    }

    .submit-file-row__input {
      position: absolute;
      inset: 0;
      width: 100%;
      height: 100%;
      opacity: 0;
      cursor: pointer;
    }

    .detail-action-wrap { width: 100%; }

    .detail-action {
      width: 100%;
      border: none;
      border-radius: 999px;
      padding: 15px 28px;
      font-family: var(--font);
      font-size: 15px;
      font-weight: 700;
      text-align: center;
      display: block;
      transition: background 0.18s ease, color 0.18s ease, border-color 0.18s ease;
    }

    .detail-action--submit {
      background: #DAE4F8;
      color: var(--blue);
      border: 2px solid transparent;
      cursor: pointer;
    }

    .detail-action--submit:hover { border-color: var(--blue); }

    .detail-action--pending {
      background: var(--card-hover);
      color: #8a5a2a;
      cursor: default;
    }

    .detail-action:disabled { opacity: 1; }

    @media (max-width: 900px) {
      .app { flex-direction: column; }
      .sidebar { width: 100%; min-height: auto; flex-direction: row; flex-wrap: wrap; padding: 20px; }
      .sidebar__brand { flex-direction: row; gap: 12px; margin-bottom: 0; width: 100%; }
      .sidebar__toggle, .sidebar__collapse { display: none !important; }
      .nav { flex-direction: row; flex-wrap: wrap; width: 100%; }
      .sidebar__spacer, .nav--bottom { display: none; }
      .main { padding: 24px 20px 40px; }
      .main__user-name { display: none; }
      .detail-head { grid-template-columns: 1fr; gap: 16px; }
      .detail-actions { justify-content: flex-start; }
      .submit-file-row { flex-direction: column; }
      .submit-file-row__upload { align-self: flex-end; }
    }

scripts.value:
(function () {
      DCEvents.renderSubmitPage();

      var app = document.querySelector('.app');
      var toggle = document.getElementById('sidebar-toggle');
      var collapse = document.getElementById('sidebar-collapse');
      var storageKey = 'dc_sidebar_collapsed';

      function setSidebarCollapsed(collapsed) {
        app.classList.toggle('is-sidebar-collapsed', collapsed);
        localStorage.setItem(storageKey, collapsed);
      }

      if (localStorage.getItem(storageKey) === 'true' && window.innerWidth > 900) {
        setSidebarCollapsed(true);
      }

      collapse.addEventListener('click', function () {
        if (window.innerWidth <= 900) return;
        setSidebarCollapsed(true);
      });

      toggle.addEventListener('click', function () {
        if (window.innerWidth <= 900) return;
        setSidebarCollapsed(false);
      });
    })();
